#include &lt;stdio.h&gt;
#include &lt;setjmp.h&gt;
#include &lt;stdlib.h&gt;

jmp_buf exception_buffer;

void deeply_nested_function(int value) {
    if (value < 0) {
        printf("FATAL: Negative value detected. Aborting!\n");
        // Instantly transports execution back to the setjmp line.
        // The '1' is the error code we send back.
        longjmp(exception_buffer, 1);
    }
    printf("Processing %d safely.\n", value);
}

int main() {
    // setjmp returns 0 exactly once when the snapshot is taken.
    // If a longjmp occurs, setjmp magically 'returns' again, yielding the longjmp value.
    int status = setjmp(exception_buffer);

    if (status == 0) {
        printf("Snapshot taken. Entering dangerous code...\n");
        deeply_nested_function(5);
        deeply_nested_function(-10); // Triggers longjmp
        printf("This line will NEVER be executed.\n");
    } else {
        printf("Caught Exception Code: %d. Recovering gracefully.\n", status);
    }

    return 0;
}

#include &lt;stdio.h&gt;
#include &lt;setjmp.h&gt;

jmp_buf env;

void trigger() { longjmp(env, 1); }

int main() {
    // Engineer tracks state across a potential failure
    int files_processed = 0;

    if (setjmp(env) == 0) {
        files_processed = 50;
        trigger();
    } else {
        // CRASH in logic: Sometimes files_processed prints 0 instead of 50!
        printf("Failed after processing %d files.\n", files_processed);
    }
    return 0;
}

