#include &lt;stdio.h&gt;
#include &lt;setjmp.h&gt;

// We hide the global jmp_buf for cleaner syntax (In real systems, this is a Stack)
jmp_buf global_ex_env;

// Elite Metaprogramming: Creating C++ syntax in C
#define TRY do { int __ex_code = setjmp(global_ex_env); if (__ex_code == 0) {
#define CATCH(x) } else if (__ex_code == (x)) {
#define CATCH_ALL } else {
#define END_TRY } } while(0)

#define THROW(x) longjmp(global_ex_env, (x))

#define ERR_DIV_ZERO 1
#define ERR_NULL_PTR 2

void do_math(int a, int b) {
    if (b == 0) THROW(ERR_DIV_ZERO);
    printf("Result: %d\n", a / b);
}

int main() {
    TRY {
        printf("Attempting Math...\n");
        do_math(10, 0);
        printf("This won't print.\n");
    } CATCH (ERR_DIV_ZERO) {
        printf("Caught Exception: Division by Zero!\n");
    } CATCH_ALL {
        printf("Caught unknown exception.\n");
    } END_TRY;

    return 0;
}

#include &lt;stdio.h&gt;
#include &lt;setjmp.h&gt;

jmp_buf env;

void inner_function() {
    // Inner function also uses setjmp to protect its own logic
    if (setjmp(env) == 0) {
        printf("Inner setup.\n");
    } else {
        printf("Inner recovered.\n");
    }
}

int main() {
    if (setjmp(env) == 0) {
        inner_function();

        // Main function hits a fatal error and tries to abort
        longjmp(env, 1);
    } else {
        // CRASH in logic: Main recovery never executes.
        printf("Main recovered.\n");
    }
    return 0;
}

#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;stdnoreturn.h&gt; // Provides the lowercase 'noreturn' macro

// We guarantee to the compiler this function never returns control.
noreturn void panic(const char *msg) {
    fprintf(stderr, "[FATAL PANIC] %s\n", msg);
    // We MUST execute a terminating function like exit() or abort().
    abort(); 
}

int divide(int a, int b) {
    if (b == 0) {
        panic("Division by zero!");

        // The compiler does NOT throw a 'missing return value' warning here.
        // It mathematically knows execution halts at the panic line.
    }
    return a / b;
}

int main() {
    divide(10, 0);
    return 0;
}

#include &lt;stdio.h&gt;
#include &lt;stdnoreturn.h&gt;

noreturn void handle_fault(int severity) {
    printf("Handling fault.\n");
    if (severity > 5) {
        // DANGER: We only exit on high severity.
        exit(1);
    }
    // If severity <= 5, the function reaches the end and attempts to return.
}

int main() {
    handle_fault(2);
    printf("Resuming normal operations...\n");
    return 0;
}
